1	//! Lock-free intrusive linked list.
2	//!
3	//! Ideas from Michael.  High Performance Dynamic Lock-Free Hash Tables and List-Based Sets.  SPAA
4	//! 2002.  <http://dl.acm.org/citation.cfm?id=564870.564881>
5	
6	use core::{
7	    marker::PhantomData,
8	    ptr::NonNull,
9	    sync::atomic::Ordering::{Acquire, Relaxed, Release},
10	};
11	
12	use crate::{Atomic, Guard, Shared, unprotected};
13	
14	/// An entry in a linked list.
15	///
16	/// An Entry is accessed from multiple threads, so it would be beneficial to put it in a different
17	/// cache-line than thread-local data in terms of performance.
18	#[derive(Debug)]
19	pub(crate) struct Entry {
20	    /// The next entry in the linked list.
21	    /// If the tag is 1, this entry is marked as deleted.
22	    next: Atomic<Entry>,
23	}
24	
25	/// Implementing this trait asserts that the type `T` can be used as an element in the intrusive
26	/// linked list defined in this module. `T` has to contain (or otherwise be linked to) an instance
27	/// of `Entry`.
28	///
29	/// # Example
30	///
31	/// ```ignore
32	/// struct A {
33	///     entry: Entry,
34	///     data: usize,
35	/// }
36	///
37	/// impl IsElement<A> for A {
38	///     fn entry_of(a: &A) -> &Entry {
39	///         let entry_ptr = ((a as usize) + offset_of!(A, entry)) as *const Entry;
40	///         unsafe { &*entry_ptr }
41	///     }
42	///
43	///     unsafe fn element_of(entry: &Entry) -> &T {
44	///         let elem_ptr = ((entry as usize) - offset_of!(A, entry)) as *const T;
45	///         &*elem_ptr
46	///     }
47	///
48	///     unsafe fn finalize(entry: &Entry, guard: &Guard) {
49	///         guard.defer_destroy(Shared::from(Self::element_of(entry) as *const _));
50	///     }
51	/// }
52	/// ```
53	///
54	/// This trait is implemented on a type separate from `T` (although it can be just `T`), because
55	/// one type might be placeable into multiple lists, in which case it would require multiple
56	/// implementations of `IsElement`. In such cases, each struct implementing `IsElement<T>`
57	/// represents a distinct `Entry` in `T`.
58	///
59	/// For example, we can insert the following struct into two lists using `entry1` for one
60	/// and `entry2` for the other:
61	///
62	/// ```ignore
63	/// struct B {
64	///     entry1: Entry,
65	///     entry2: Entry,
66	///     data: usize,
67	/// }
68	/// ```
69	///
70	pub(crate) trait IsElement<T> {
71	    /// Returns a pointer to this element's `Entry`.
72	    fn entry_of(_: *const T) -> *const Entry;
73	
74	    /// Given a pointer to an element's entry, returns that element.
75	    ///
76	    /// ```ignore
77	    /// let elem = ListElement::new();
78	    /// assert_eq!(elem.entry_of(),
79	    ///            unsafe { ListElement::element_of(elem.entry_of()) } );
80	    /// ```
81	    ///
82	    /// # Safety
83	    ///
84	    /// The caller has to guarantee that the `Entry` is called with was retrieved from an instance
85	    /// of the element type (`T`).
86	    unsafe fn element_of(_: *const Entry) -> *const T;
87	
88	    /// The function that is called when an entry is unlinked from list.
89	    ///
90	    /// # Safety
91	    ///
92	    /// The caller has to guarantee that the `Entry` is called with was retrieved from an instance
93	    /// of the element type (`T`).
94	    unsafe fn finalize(_: *const Entry, _: &Guard);
95	}
96	
97	/// A lock-free, intrusive linked list of type `T`.
98	#[derive(Debug)]
99	pub(crate) struct List<T, C: IsElement<T> = T> {
100	    /// The head of the linked list.
101	    head: Atomic<Entry>,
102	
103	    /// The phantom data for using `T` and `C`.
104	    _marker: PhantomData<(T, C)>,
105	}
106	
107	/// An iterator used for retrieving values from the list.
108	pub(crate) struct Iter<'g, T, C: IsElement<T>> {
109	    /// The guard that protects the iteration.
110	    guard: &'g Guard,
111	
112	    /// Pointer from the predecessor to the current entry.
113	    pred: &'g Atomic<Entry>,
114	
115	    /// The current entry.
116	    curr: Shared<'g, Entry>,
117	
118	    /// The list head, needed for restarting iteration.
119	    head: &'g Atomic<Entry>,
120	
121	    /// Logically, we store a borrow of an instance of `T` and
122	    /// use the type information from `C`.
123	    _marker: PhantomData<(&'g T, C)>,
124	}
125	
126	/// An error that occurs during iteration over the list.
127	#[derive(PartialEq, Debug)]
128	pub(crate) enum IterError {
129	    /// A concurrent thread modified the state of the list at the same place that this iterator
130	    /// was inspecting. Subsequent iteration will restart from the beginning of the list.
131	    Stalled,
132	}
133	
134	impl Default for Entry {
135	    /// Returns the empty entry.
136	    fn default() -> Self {
137	        Self {
138	            next: Atomic::null(),
139	        }
140	    }
141	}
142	
143	impl Entry {
144	    /// Marks this entry as deleted, deferring the actual deallocation to a later iteration.
145	    ///
146	    /// # Safety
147	    ///
148	    /// The entry should be a member of a linked list, and it should not have been deleted.
149	    /// It should be safe to call `C::finalize` on the entry after the `guard` is dropped, where `C`
150	    /// is the associated helper for the linked list.
151	    pub(crate) unsafe fn delete(&self, guard: &Guard) {
152	        self.next.fetch_or(1, Release, guard);
153	    }
154	}
155	
156	impl<T, C: IsElement<T>> List<T, C> {
157	    /// Returns a new, empty linked list.
158	    pub(crate) fn new() -> Self {
159	        Self {
160	            head: Atomic::null(),
161	            _marker: PhantomData,
162	        }
163	    }
164	
165	    /// Inserts `entry` into the head of the list.
166	    ///
167	    /// # Safety
168	    ///
169	    /// You should guarantee that:
170	    ///
171	    /// - `container` is not null
172	    /// - `container` is immovable, e.g. inside an `Owned`
173	    /// - the same `Entry` is not inserted more than once
174	    /// - the inserted object will be removed before the list is dropped
175	    pub(crate) unsafe fn insert<'g>(&'g self, container: Shared<'g, T>, guard: &'g Guard) {
176	        // Insert right after head, i.e. at the beginning of the list.
177	        let to = &self.head;
178	        // Get the intrusively stored Entry of the new element to insert.
179	        let entry: *const Entry = C::entry_of(unsafe { container.as_ptr() });
180	        // Make a Shared ptr to that Entry.
181	        let entry_ptr = Shared::from(entry);
182	        // Read the current successor of where we want to insert.
183	        let mut next = to.load(Relaxed, guard);
184	
185	        loop {
186	            // Set the Entry of the to-be-inserted element to point to the previous successor of
187	            // `to`.
188	            unsafe { (*entry).next.store(next, Relaxed) }
189	            match to.compare_exchange_weak(next, entry_ptr, Release, Relaxed, guard) {
190	                Ok(_) => break,
191	                // We lost the race or weak CAS failed spuriously. Update the successor and try
192	                // again.
193	                Err(err) => next = err.current,
194	            }
195	        }
196	    }
197	
198	    /// Returns an iterator over all objects.
199	    ///
200	    /// # Caveat
201	    ///
202	    /// Every object that is inserted at the moment this function is called and persists at least
203	    /// until the end of iteration will be returned. Since this iterator traverses a lock-free
204	    /// linked list that may be concurrently modified, some additional caveats apply:
205	    ///
206	    /// 1. If a new object is inserted during iteration, it may or may not be returned.
207	    /// 2. If an object is deleted during iteration, it may or may not be returned.
208	    /// 3. The iteration may be aborted when it lost in a race condition. In this case, the winning
209	    ///    thread will continue to iterate over the same list.
210	    pub(crate) fn iter<'g>(&'g self, guard: &'g Guard) -> Iter<'g, T, C> {
211	        Iter {
212	            guard,
213	            pred: &self.head,
214	            curr: self.head.load(Acquire, guard),
215	            head: &self.head,
216	            _marker: PhantomData,
217	        }
218	    }
219	}
